import { getPlanEndDate } from "../utils/membership";
import { clearSession } from "./auth";

const STORAGE_KEY = "pulsefit-mock-db-v1";

function formatDate(date) {
  return date.toISOString().split("T")[0];
}

function daysFromToday(days) {
  const date = new Date();
  date.setHours(0, 0, 0, 0);
  date.setDate(date.getDate() + days);
  return formatDate(date);
}

function createDefaultGyms() {
  return [
    {
      gymId: "ADMIN001",
      role: "admin",
      name: "Product Admin",
      email: "productadmin@pulsefit.com",
      password: "1234",
      status: "Active",
      phone: "9000000000",
      city: "Bengaluru",
      joinedOn: daysFromToday(-120),
      updatedAt: daysFromToday(-1)
    },
    {
      gymId: "GYM001",
      role: "owner",
      gymName: "Iron Forge Fitness",
      ownerName: "Aarav Sharma",
      email: "aarav@ironforge.com",
      password: "1234",
      phone: "9876500011",
      city: "Hyderabad",
      status: "Active",
      joinedOn: daysFromToday(-90),
      updatedAt: daysFromToday(-2)
    },
    {
      gymId: "GYM002",
      role: "owner",
      gymName: "Core District Gym",
      ownerName: "Meera Iyer",
      email: "meera@coredistrict.com",
      password: "1234",
      phone: "9876500022",
      city: "Chennai",
      status: "Pending",
      joinedOn: daysFromToday(-35),
      updatedAt: daysFromToday(-5)
    },
    {
      gymId: "GYM003",
      role: "owner",
      gymName: "Titan House",
      ownerName: "Rohan Patel",
      email: "rohan@titanhouse.com",
      password: "1234",
      phone: "9876500033",
      city: "Pune",
      status: "Suspended",
      joinedOn: daysFromToday(-180),
      updatedAt: daysFromToday(-12)
    }
  ];
}

function createDefaultCustomers() {
  return [
    {
      gymId: "GYM001",
      customerId: 1,
      fullName: "Sarah Khan",
      phone: "9876543210",
      age: 27,
      plan: "1 Month",
      amountPaid: 1500,
      planStart: daysFromToday(-5),
      planEnd: getPlanEndDate(daysFromToday(-5), "1 Month"),
      lastAttended: daysFromToday(0),
      status: "Active"
    },
    {
      gymId: "GYM001",
      customerId: 2,
      fullName: "Arjun Mehta",
      phone: "9811122233",
      age: 31,
      plan: "1 Month",
      amountPaid: 1600,
      planStart: daysFromToday(-28),
      planEnd: getPlanEndDate(daysFromToday(-28), "1 Month"),
      lastAttended: daysFromToday(-1),
      status: "Active"
    },
    {
      gymId: "GYM001",
      customerId: 3,
      fullName: "Neha Reddy",
      phone: "9822233344",
      age: 24,
      plan: "1 Month",
      amountPaid: 1400,
      planStart: daysFromToday(-40),
      planEnd: getPlanEndDate(daysFromToday(-40), "1 Month"),
      lastAttended: daysFromToday(-10),
      status: "Expired"
    },
    {
      gymId: "GYM001",
      customerId: 4,
      fullName: "Vikram Singh",
      phone: "9833344455",
      age: 29,
      plan: "3 Months",
      amountPaid: 4200,
      planStart: daysFromToday(-20),
      planEnd: getPlanEndDate(daysFromToday(-20), "3 Months"),
      lastAttended: "",
      status: "Active"
    },
    {
      gymId: "GYM002",
      customerId: 1,
      fullName: "Kavya Menon",
      phone: "9844455566",
      age: 26,
      plan: "1 Month",
      amountPaid: 1800,
      planStart: daysFromToday(-8),
      planEnd: getPlanEndDate(daysFromToday(-8), "1 Month"),
      lastAttended: daysFromToday(-2),
      status: "Active"
    },
    {
      gymId: "GYM002",
      customerId: 2,
      fullName: "Harish Nair",
      phone: "9855566677",
      age: 33,
      plan: "3 Months",
      amountPaid: 4500,
      planStart: daysFromToday(-42),
      planEnd: getPlanEndDate(daysFromToday(-42), "3 Months"),
      lastAttended: daysFromToday(-4),
      status: "Active"
    },
    {
      gymId: "GYM003",
      customerId: 1,
      fullName: "Ishita Desai",
      phone: "9866677788",
      age: 22,
      plan: "1 Month",
      amountPaid: 1500,
      planStart: daysFromToday(-15),
      planEnd: getPlanEndDate(daysFromToday(-15), "1 Month"),
      lastAttended: "",
      status: "Active"
    }
  ];
}

function createDefaultDatabase() {
  return {
    gyms: createDefaultGyms(),
    customers: createDefaultCustomers(),
    attendances: []
  };
}

function readDatabase() {
  const raw = localStorage.getItem(STORAGE_KEY);

  if (!raw) {
    const database = createDefaultDatabase();
    writeDatabase(database);
    return database;
  }

  try {
    return JSON.parse(raw);
  } catch (error) {
    const database = createDefaultDatabase();
    writeDatabase(database);
    return database;
  }
}

function writeDatabase(database) {
  localStorage.setItem(STORAGE_KEY, JSON.stringify(database));
}

function buildResponse(data) {
  return Promise.resolve({ data });
}

function buildError(status, message) {
  return Promise.reject({
    response: {
      status,
      data: { message }
    }
  });
}

function getSessionFromToken() {
  const token = localStorage.getItem("token");

  if (!token || !token.startsWith("mock-token:")) {
    return null;
  }

  const [, role, gymId] = token.split(":");

  if (!role || !gymId) {
    return null;
  }

  return { role, gymId };
}

function requireAuth() {
  const session = getSessionFromToken();

  if (!session) {
    throw {
      response: {
        status: 401,
        data: { message: "No token" }
      }
    };
  }

  return session;
}

function requireOwnerAuth() {
  const session = requireAuth();

  if (session.role !== "owner") {
    throw {
      response: {
        status: 403,
        data: { message: "Owner access required." }
      }
    };
  }

  return session;
}

function requireAdminAuth() {
  const session = requireAuth();

  if (session.role !== "admin") {
    throw {
      response: {
        status: 403,
        data: { message: "Admin access required." }
      }
    };
  }

  return session;
}

function getNotifications(customers) {
  const today = new Date();
  today.setHours(0, 0, 0, 0);

  return customers
    .map((customer) => {
      const planEnd = new Date(`${customer.planEnd}T00:00:00`);
      const diff =
        (planEnd.getTime() - today.getTime()) / (1000 * 60 * 60 * 24);

      if (diff < 0) {
        return { name: customer.fullName, type: "expired" };
      }

      if (diff <= 3) {
        return { name: customer.fullName, type: "expiring" };
      }

      return null;
    })
    .filter(Boolean);
}

function mapGymOwnerRecord(gym, customers) {
  return {
    gymId: gym.gymId,
    gymName: gym.gymName,
    ownerName: gym.ownerName,
    email: gym.email,
    phone: gym.phone,
    city: gym.city,
    status: gym.status,
    joinedOn: gym.joinedOn,
    updatedAt: gym.updatedAt,
    customerCount: customers.filter((customer) => customer.gymId === gym.gymId).length
  };
}

function buildMockSession(user) {
  return {
    token: `mock-token:${user.role}:${user.gymId}`,
    user: {
      role: user.role,
      gymId: user.gymId,
      email: user.email,
      name: user.role === "admin" ? user.name : user.ownerName
    }
  };
}

function validateGymOwnerPayload(database, payload, currentGymId = null) {
  if (
    !payload.gymId ||
    !payload.gymName ||
    !payload.ownerName ||
    !payload.email ||
    !payload.phone ||
    !payload.city ||
    !payload.status
  ) {
    return "Please complete all gym owner fields before saving.";
  }

  const duplicateGym = database.gyms.find(
    (gym) =>
      gym.role === "owner" &&
      gym.gymId === payload.gymId &&
      gym.gymId !== currentGymId
  );

  if (duplicateGym) {
    return "That gym ID is already in use.";
  }

  const duplicateEmail = database.gyms.find(
    (gym) =>
      gym.role === "owner" &&
      gym.email.toLowerCase() === payload.email.toLowerCase() &&
      gym.gymId !== currentGymId
  );

  if (duplicateEmail) {
    return "That email address is already assigned to another gym owner.";
  }

  return "";
}

const mockApi = {
  get(path) {
    if (path === "/seed") {
      const database = createDefaultDatabase();
      writeDatabase(database);
      clearSession();
      return buildResponse("Demo users created");
    }

    if (path === "/customers") {
      try {
        const session = requireOwnerAuth();
        const database = readDatabase();
        const customers = database.customers.filter(
          (customer) => customer.gymId === session.gymId
        );
        return buildResponse(customers);
      } catch (error) {
        return Promise.reject(error);
      }
    }

    if (path === "/notifications") {
      try {
        const session = requireOwnerAuth();
        const database = readDatabase();
        const customers = database.customers.filter(
          (customer) => customer.gymId === session.gymId
        );
        return buildResponse(getNotifications(customers));
      } catch (error) {
        return Promise.reject(error);
      }
    }

    if (path === "/admin/gym-owners") {
      try {
        requireAdminAuth();
        const database = readDatabase();
        const gymOwners = database.gyms
          .filter((gym) => gym.role === "owner")
          .map((gym) => mapGymOwnerRecord(gym, database.customers))
          .sort((left, right) => left.gymId.localeCompare(right.gymId));

        return buildResponse(gymOwners);
      } catch (error) {
        return Promise.reject(error);
      }
    }

    return buildError(404, "Mock route not found.");
  },

  post(path, payload) {
    if (path === "/login") {
      const database = readDatabase();
      const user = database.gyms.find(
        (item) => item.email.toLowerCase() === payload.email.toLowerCase()
      );

      if (!user || user.password !== payload.password) {
        return buildError(401, "Invalid");
      }

      return buildResponse(buildMockSession(user));
    }

    if (path === "/customers") {
      try {
        const session = requireOwnerAuth();
        const database = readDatabase();
        const gymCustomers = database.customers.filter(
          (customer) => customer.gymId === session.gymId
        );
        const today = formatDate(new Date());

        const customer = {
          gymId: session.gymId,
          customerId: gymCustomers.length + 1,
          fullName: payload.fullName,
          phone: payload.phone,
          age: payload.age,
          plan: payload.plan,
          amountPaid: payload.amountPaid,
          planStart: today,
          planEnd: getPlanEndDate(today, payload.plan),
          lastAttended: "",
          status: "Active"
        };

        database.customers.push(customer);
        writeDatabase(database);

        return buildResponse(customer);
      } catch (error) {
        return Promise.reject(error);
      }
    }

    if (path === "/customers/attendance") {
      try {
        const session = requireOwnerAuth();
        const database = readDatabase();
        const customer = database.customers.find(
          (item) =>
            item.gymId === session.gymId &&
            item.customerId === Number(payload.customerId)
        );

        if (!customer) {
          return buildError(404, "Not found");
        }

        const today = formatDate(new Date());
        customer.lastAttended = today;
        database.attendances.push({
          gymId: session.gymId,
          customerId: customer.customerId,
          date: today
        });
        writeDatabase(database);

        return buildResponse(customer);
      } catch (error) {
        return Promise.reject(error);
      }
    }

    if (path === "/admin/gym-owners") {
      try {
        requireAdminAuth();
        const database = readDatabase();
        const nextPayload = {
          ...payload,
          gymId: payload.gymId?.trim().toUpperCase(),
          email: payload.email?.trim().toLowerCase()
        };
        const message = validateGymOwnerPayload(database, nextPayload);

        if (message) {
          return buildError(400, message);
        }

        const today = formatDate(new Date());
        const owner = {
          gymId: nextPayload.gymId,
          role: "owner",
          gymName: nextPayload.gymName.trim(),
          ownerName: nextPayload.ownerName.trim(),
          email: nextPayload.email,
          password: payload.password?.trim() || "1234",
          phone: nextPayload.phone.trim(),
          city: nextPayload.city.trim(),
          status: nextPayload.status,
          joinedOn: today,
          updatedAt: today
        };

        database.gyms.push(owner);
        writeDatabase(database);

        return buildResponse(mapGymOwnerRecord(owner, database.customers));
      } catch (error) {
        return Promise.reject(error);
      }
    }

    return buildError(404, "Mock route not found.");
  },

  put(path, payload) {
    if (!path.startsWith("/admin/gym-owners/")) {
      return buildError(404, "Mock route not found.");
    }

    try {
      requireAdminAuth();
      const database = readDatabase();
      const currentGymId = decodeURIComponent(path.replace("/admin/gym-owners/", ""));
      const gym = database.gyms.find(
        (item) => item.role === "owner" && item.gymId === currentGymId
      );

      if (!gym) {
        return buildError(404, "Gym owner not found.");
      }

      const nextPayload = {
        ...payload,
        gymId: payload.gymId?.trim().toUpperCase()
      };
      const message = validateGymOwnerPayload(database, nextPayload, currentGymId);

      if (message) {
        return buildError(400, message);
      }

      gym.gymId = nextPayload.gymId;
      gym.gymName = nextPayload.gymName.trim();
      gym.ownerName = nextPayload.ownerName.trim();
      gym.email = nextPayload.email.trim().toLowerCase();
      gym.phone = nextPayload.phone.trim();
      gym.city = nextPayload.city.trim();
      gym.status = nextPayload.status;
      gym.updatedAt = formatDate(new Date());

      if (payload.password?.trim()) {
        gym.password = payload.password.trim();
      }

      if (currentGymId !== gym.gymId) {
        database.customers.forEach((customer) => {
          if (customer.gymId === currentGymId) {
            customer.gymId = gym.gymId;
          }
        });
        database.attendances.forEach((attendance) => {
          if (attendance.gymId === currentGymId) {
            attendance.gymId = gym.gymId;
          }
        });
      }

      writeDatabase(database);

      return buildResponse(mapGymOwnerRecord(gym, database.customers));
    } catch (error) {
      return Promise.reject(error);
    }
  }
};

export default mockApi;
